  "inlineSchema": "// ─────────────────────────────────────────────────────────\n// backend/src/prisma/schema.prisma — Schéma de base de données\n// ResearchCall MVP — Phase 1\n//\n// Modèles : User, Call, Attachment, Favorite, Notification\n// Base : PostgreSQL\n// ─────────────────────────────────────────────────────────\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ═══════════════════════════════════════════════════════════\n// USER — Utilisateur (Chercheur / Publicateur / Admin)\n// ═══════════════════════════════════════════════════════════\n\nenum UserRole {\n  seeker\n  publisher\n  both\n  admin\n}\n\nmodel User {\n  id           String   @id @default(uuid())\n  email        String   @unique\n  passwordHash String   @map(\"password_hash\")\n  firstName    String   @map(\"first_name\")\n  lastName     String   @map(\"last_name\")\n  role         UserRole @default(both)\n  institution  String?\n  laboratory   String?\n  domains      String[] @default([])\n  interests    String[] @default([])\n  avatarUrl    String?  @map(\"avatar_url\")\n  pushToken    String?  @map(\"push_token\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  publishedCalls Call[]         @relation(\"PublishedCalls\")\n  favorites      Favorite[]\n  notifications  Notification[]\n  refreshTokens  RefreshToken[]\n\n  @@map(\"users\")\n}\n\n// ═══════════════════════════════════════════════════════════\n// REFRESH TOKEN — Tokens de rafraîchissement\n// ═══════════════════════════════════════════════════════════\n\nmodel RefreshToken {\n  id        String   @id @default(uuid())\n  token     String   @unique\n  userId    String   @map(\"user_id\")\n  expiresAt DateTime @map(\"expires_at\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@map(\"refresh_tokens\")\n}\n\n// ═══════════════════════════════════════════════════════════\n// CALL — Appel (Communication, Publication, Colloque…)\n// ═══════════════════════════════════════════════════════════\n\nenum CallType {\n  communication\n  publication\n  colloque\n  projet\n  bourse\n  autre\n}\n\nenum CallStatus {\n  draft\n  pending\n  published\n  expired\n  rejected\n}\n\nenum LocationModality {\n  presentiel\n  en_ligne\n  hybride\n}\n\nmodel Call {\n  id          String     @id @default(uuid())\n  publisherId String     @map(\"publisher_id\")\n  title       String\n  type        CallType\n  description String     @db.Text\n  status      CallStatus @default(pending)\n\n  // Taxonomie\n  thematicAxes String[] @default([]) @map(\"thematic_axes\")\n  domains      String[] @default([])\n  language     String   @default(\"fr\")\n\n  // Dates\n  submissionDeadline DateTime  @map(\"submission_deadline\")\n  notificationDate   DateTime? @map(\"notification_date\")\n  eventStartDate     DateTime? @map(\"event_start_date\")\n  eventEndDate       DateTime? @map(\"event_end_date\")\n\n  // Lieu\n  locationCity     String?          @map(\"location_city\")\n  locationCountry  String?          @map(\"location_country\")\n  locationModality LocationModality @default(presentiel) @map(\"location_modality\")\n\n  // Conditions & contact\n  submissionConditions String? @map(\"submission_conditions\") @db.Text\n  contactEmail         String  @map(\"contact_email\")\n  externalUrl          String? @map(\"external_url\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  publisher   User         @relation(\"PublishedCalls\", fields: [publisherId], references: [id], onDelete: Cascade)\n  attachments Attachment[]\n  favorites   Favorite[]\n\n  // Index pour la recherche et le tri\n  @@index([publisherId])\n  @@index([status])\n  @@index([type])\n  @@index([submissionDeadline])\n  @@index([createdAt])\n  @@index([domains])\n  @@map(\"calls\")\n}\n\n// ═══════════════════════════════════════════════════════════\n// ATTACHMENT — Pièce jointe\n// ═══════════════════════════════════════════════════════════\n\nmodel Attachment {\n  id       String @id @default(uuid())\n  callId   String @map(\"call_id\")\n  fileName String @map(\"file_name\")\n  fileUrl  String @map(\"file_url\")\n  fileSize Int    @map(\"file_size\") // En octets\n  mimeType String @map(\"mime_type\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  call Call @relation(fields: [callId], references: [id], onDelete: Cascade)\n\n  @@index([callId])\n  @@map(\"attachments\")\n}\n\n// ═══════════════════════════════════════════════════════════\n// FAVORITE — Appels sauvegardés\n// ═══════════════════════════════════════════════════════════\n\nmodel Favorite {\n  id     String @id @default(uuid())\n  userId String @map(\"user_id\")\n  callId String @map(\"call_id\")\n\n  savedAt DateTime @default(now()) @map(\"saved_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n  call Call @relation(fields: [callId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, callId])\n  @@index([userId])\n  @@index([callId])\n  @@map(\"favorites\")\n}\n\n// ═══════════════════════════════════════════════════════════\n// NOTIFICATION — Notifications utilisateur\n// ═══════════════════════════════════════════════════════════\n\nenum NotificationType {\n  new_call\n  deadline_reminder\n  moderation_result\n}\n\nmodel Notification {\n  id     String           @id @default(uuid())\n  userId String           @map(\"user_id\")\n  callId String?          @map(\"call_id\")\n  title  String\n  body   String\n  type   NotificationType\n  isRead Boolean          @default(false) @map(\"is_read\")\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([userId, isRead])\n  @@map(\"notifications\")\n}\n",
